 1→import { readFileSync } from "node:fs";
 2→import path from "node:path";
 3→import { AGENT_IDS } from "../types.ts";
 4→import type { AgentId, Manifest, SkillEntry } from "../types.ts";
 5→
 6→export function loadManifest(directory: string): Manifest {
 7→  const manifestPath = path.join(directory, "inception.json");
 8→
 9→  let raw: string;
10→  try {
11→    raw = readFileSync(manifestPath, "utf-8");
12→  } catch {
13→    throw new Error(
14→      `No inception.json found in ${directory}. Are you pointing to the right repo?`
15→    );
16→  }
17→
18→  let parsed: unknown;
19→  try {
20→    parsed = JSON.parse(raw);
21→  } catch {
22→    throw new Error(`Invalid JSON in ${manifestPath}`);
23→  }
24→
25→  return validateManifest(parsed, manifestPath);
26→}
27→
28→function validateManifest(data: unknown, filePath: string): Manifest {
29→  if (typeof data !== "object" || data === null || Array.isArray(data)) {
30→    throw new Error(`${filePath}: manifest must be a JSON object`);
31→  }
32→
33→  const obj = data as Record<string, unknown>;
34→
35→  if (!Array.isArray(obj.skills)) {
36→    throw new Error(`${filePath}: "skills" must be an array`);
37→  }
38→
39→  const skills: SkillEntry[] = obj.skills.map((entry: unknown, i: number) => {
40→    if (typeof entry !== "object" || entry === null || Array.isArray(entry)) {
41→      throw new Error(`${filePath}: skills[${i}] must be an object`);
42→    }
43→
44→    const skill = entry as Record<string, unknown>;
45→
46→    if (typeof skill.name !== "string" || skill.name.length === 0) {
47→      throw new Error(`${filePath}: skills[${i}].name must be a non-empty string`);
48→    }
49→
50→    if (typeof skill.path !== "string" || skill.path.length === 0) {
51→      throw new Error(`${filePath}: skills[${i}].path must be a non-empty string`);
52→    }
53→
54→    if (!Array.isArray(skill.agents) || skill.agents.length === 0) {
55→      throw new Error(`${filePath}: skills[${i}].agents must be a non-empty array`);
56→    }
57→
58→    for (const agent of skill.agents) {
59→      if (!AGENT_IDS.includes(agent as AgentId)) {
60→        throw new Error(
61→          `${filePath}: skills[${i}].agents contains unknown agent "${agent}". Valid agents: ${AGENT_IDS.join(", ")}`
62→        );
63→      }
64→    }
65→
66→    return {
67→      name: skill.name,
68→      path: skill.path,
69→      agents: skill.agents as AgentId[],
70→    };
71→  });
72→
73→  return {
74→    skills,
75→    mcpServers: Array.isArray(obj.mcpServers) ? obj.mcpServers : [],
76→    agentRules: Array.isArray(obj.agentRules) ? obj.agentRules : [],
77→  };
78→}
