  1→#!/usr/bin/env node
  2→
  3→import path from "node:path";
  4→import { AGENT_IDS } from "./types.ts";
  5→import type { AgentId, CliOptions } from "./types.ts";
  6→import { loadManifest } from "./config/manifest.ts";
  7→import { AGENT_REGISTRY } from "./config/agents.ts";
  8→import { resolveHome } from "./core/resolve.ts";
  9→import { detectInstalledAgents } from "./core/detect.ts";
 10→import { planDeploy, executeDeploy } from "./core/deploy.ts";
 11→import { planRevert, executeRevert } from "./core/revert.ts";
 12→
 13→const USAGE = `
 14→inception-engine - Deploy AI agent skills
 15→
 16→Usage:
 17→  inception-engine <directory> [options]
 18→  inception-engine revert <directory> [options]
 19→
 20→Options:
 21→  --dry-run        Show what would be done without doing it
 22→  --agents <list>  Comma-separated list of agent IDs to target
 23→  --verbose        Show detailed output
 24→  --help           Show this help message
 25→
 26→Supported agents:
 27→  ${AGENT_REGISTRY.map((a) => `${a.id} (${a.displayName})`).join(", ")}
 28→`.trim();
 29→
 30→function parseArgs(argv: string[]): CliOptions {
 31→  const args = argv.slice(2);
 32→
 33→  if (args.length === 0 || args.includes("--help")) {
 34→    return { command: "help", directory: "", dryRun: false, agents: null, verbose: false };
 35→  }
 36→
 37→  let command: "deploy" | "revert" = "deploy";
 38→  let directory = "";
 39→  let dryRun = false;
 40→  let agents: AgentId[] | null = null;
 41→  let verbose = false;
 42→
 43→  let i = 0;
 44→  if (args[0] === "revert") {
 45→    command = "revert";
 46→    i = 1;
 47→  }
 48→
 49→  while (i < args.length) {
 50→    const arg = args[i]!;
 51→
 52→    if (arg === "--dry-run") {
 53→      dryRun = true;
 54→    } else if (arg === "--verbose") {
 55→      verbose = true;
 56→    } else if (arg === "--agents") {
 57→      i++;
 58→      const next = args[i];
 59→      if (!next) {
 60→        console.error("--agents requires a comma-separated list");
 61→        process.exit(1);
 62→      }
 63→      const ids = next.split(",").map((s) => s.trim());
 64→      for (const id of ids) {
 65→        if (!AGENT_IDS.includes(id as AgentId)) {
 66→          console.error(`Unknown agent: "${id}". Valid agents: ${AGENT_IDS.join(", ")}`);
 67→          process.exit(1);
 68→        }
 69→      }
 70→      agents = ids as AgentId[];
 71→    } else if (arg.startsWith("--")) {
 72→      console.error(`Unknown option: ${arg}`);
 73→      process.exit(1);
 74→    } else if (!directory) {
 75→      directory = arg;
 76→    } else {
 77→      console.error(`Unexpected argument: ${arg}`);
 78→      process.exit(1);
 79→    }
 80→    i++;
 81→  }
 82→
 83→  if (!directory) {
 84→    console.error("Missing required <directory> argument");
 85→    process.exit(1);
 86→  }
 87→
 88→  return { command, directory: path.resolve(directory), dryRun, agents, verbose };
 89→}
 90→
 91→function main(): void {
 92→  const options = parseArgs(process.argv);
 93→
 94→  if (options.command === "help") {
 95→    console.log(USAGE);
 96→    process.exit(0);
 97→  }
 98→
 99→  const manifest = loadManifest(options.directory);
100→  const home = resolveHome();
101→
102→  let detectedAgents: AgentId[];
103→  if (options.agents) {
104→    detectedAgents = options.agents;
105→    if (options.verbose) {
106→      console.log(`Using specified agents: ${detectedAgents.join(", ")}`);
107→    }
108→  } else {
109→    detectedAgents = detectInstalledAgents(home);
110→    if (detectedAgents.length === 0) {
111→      console.log("No supported AI agents detected on this system.");
112→      console.log(`Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`);
113→      process.exit(0);
114→    }
115→    if (options.verbose) {
116→      console.log(`Detected agents: ${detectedAgents.join(", ")}`);
117→    }
118→  }
119→
120→  const prefix = options.dryRun ? "\x1b[36m[dry-run]\x1b[0m " : "";
121→
122→  if (options.command === "deploy") {
123→    const actions = planDeploy(manifest, options.directory, detectedAgents, home);
124→    if (actions.length === 0) {
125→      console.log("No skills to deploy for detected agents.");
126→      return;
127→    }
128→
129→    console.log(`${prefix}Deploying ${actions.length} skill(s):`);
130→    const { succeeded, failed } = executeDeploy(actions, options.dryRun, options.verbose);
131→
132→    console.log();
133→    if (failed.length > 0) {
134→      console.log(`${succeeded} succeeded, ${failed.length} failed`);
135→      process.exit(1);
136→    } else {
137→      console.log(`${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`);
138→    }
139→  } else {
140→    const actions = planRevert(manifest, detectedAgents, home);
141→    if (actions.length === 0) {
142→      console.log("No skills to revert for detected agents.");
143→      return;
144→    }
145→
146→    console.log(`${prefix}Reverting ${actions.length} skill(s):`);
147→    const { succeeded, skipped } = executeRevert(actions, options.dryRun, options.verbose);
148→
149→    console.log();
150→    const parts = [`${succeeded} removed`];
151→    if (skipped > 0) parts.push(`${skipped} skipped`);
152→    console.log(`${parts.join(", ")}${options.dryRun ? " (dry-run)" : ""}`);
153→  }
154→}
155→
156→main();
