 1→import { existsSync } from "node:fs";
 2→import { execFileSync } from "node:child_process";
 3→import { AGENT_REGISTRY } from "../config/agents.ts";
 4→import { resolveAgentDetectPath } from "./resolve.ts";
 5→import type { AgentId, AgentConfig } from "../types.ts";
 6→
 7→export function detectInstalledAgents(home: string): AgentId[] {
 8→  const detected: AgentId[] = [];
 9→
10→  for (const agent of AGENT_REGISTRY) {
11→    if (isAgentInstalled(agent, home)) {
12→      detected.push(agent.id);
13→    }
14→  }
15→
16→  return detected;
17→}
18→
19→function isAgentInstalled(agent: AgentConfig, home: string): boolean {
20→  const detectPath = resolveAgentDetectPath(agent, home);
21→  if (existsSync(detectPath)) {
22→    return true;
23→  }
24→
25→  if (agent.detectBinary) {
26→    return isBinaryInPath(agent.detectBinary);
27→  }
28→
29→  return false;
30→}
31→
32→function isBinaryInPath(binary: string): boolean {
33→  const command = process.platform === "win32" ? "where.exe" : "which";
34→  try {
35→    execFileSync(command, [binary], { stdio: "ignore" });
36→    return true;
37→  } catch {
38→    return false;
39→  }
40→}
