 8→  detectedAgents: AgentId[],
 9→  home: string
10→): RevertAction[] {
11→  const actions: RevertAction[] = [];
12→
13→  for (const skill of manifest.skills) {
14→    for (const agentId of skill.agents) {
15→      if (!detectedAgents.includes(agentId)) continue;
16→
17→      const agent = AGENT_REGISTRY.find((a) => a.id === agentId);
18→      if (!agent) continue;
19→
20→      const target = resolveAgentSkillPath(agent, skill.name, home);
